.load extensions/pdf-meta/target/wasm32-wasip2/release/pdf_meta_extension.component.wasm

/* PDF metadata extraction.
 *
 * Per PLAN-more-extensions-4.md §1 acceptance:
 *   - Fixture PDF with known metadata: each field extracted
 *   - pdf_page_count on a 3-page PDF == 3
 *   - Random bytes -> every fn returns NULL
 *   - Encrypted PDF -> pdf_is_encrypted == 1, title/author still extract
 *   - Truncated PDF (header only) -> pdf_pdf_version still extracts
 *
 * Fixtures (all hex literals):
 *
 *   pdf_a (603 bytes): minimal PDF 1.7 with 1 page and a full
 *     /Info dictionary -- Title=Test PDF, Author=Test Author,
 *     Subject=Test Subject, Keywords=kw1, kw2,
 *     Creator=Test Creator, Producer=Test Producer,
 *     CreationDate=D:20240115103045Z, ModDate=D:20240116113045Z.
 *
 *   pdf_b (827 bytes): same shape, 3 pages -- exercises the
 *     pdf_page_count walk through the /Pages tree.
 *
 *   pdf_c (15 bytes): header-only "%PDF-2.0\n%<binary marker>"
 *     truncated file -- lopdf parse fails, header byte scan still
 *     extracts the version per the acceptance bullet.
 *
 *   pdf_enc (784 bytes): PDF 1.7 with a Standard V=1 R=2 RC4-40
 *     encryption dictionary (placeholder O/U strings) referenced
 *     from the trailer. lopdf flags it encrypted; /Info dict lives
 *     in cleartext so Title/Author still extract.
 *
 *   random:      16 bytes of 0xAA -- matches no PDF marker, every
 *     scalar returns NULL (the contract for non-PDF input).
 */

------------------------------------------------------------------
-- Acceptance 1: full single-page PDF -> every /Info field
------------------------------------------------------------------
SELECT pdf_title(x'');
SELECT pdf_author(x'');
SELECT pdf_subject(x'');
SELECT pdf_creator(x'');
SELECT pdf_producer(x'');
SELECT pdf_keywords(x'');
SELECT pdf_creation_date(x'');
SELECT pdf_mod_date(x'');
SELECT pdf_page_count(x'');
SELECT pdf_pdf_version(x'');
SELECT pdf_is_encrypted(x'');

------------------------------------------------------------------
-- Acceptance 2: 3-page PDF -> pdf_page_count == 3
------------------------------------------------------------------
SELECT pdf_page_count(x'');
SELECT pdf_pdf_version(x'');

------------------------------------------------------------------
-- Acceptance 3: truncated PDF (header only) -> version still extracts
-- Other accessors NULL because lopdf can't parse the body.
------------------------------------------------------------------
SELECT pdf_pdf_version(x'255044462D322E300A25E2E3CFD30A');
SELECT pdf_title(x'255044462D322E300A25E2E3CFD30A');
SELECT pdf_page_count(x'255044462D322E300A25E2E3CFD30A');

------------------------------------------------------------------
-- Acceptance 4: encrypted PDF -> is_encrypted == 1; metadata extracts
------------------------------------------------------------------
SELECT pdf_is_encrypted(x'');
SELECT pdf_title(x'');
SELECT pdf_author(x'');

------------------------------------------------------------------
-- Acceptance 5: pdf_all returns parseable JSON with the same fields
------------------------------------------------------------------
SELECT json_extract(pdf_all(x''), '$.title');
SELECT json_extract(pdf_all(x''), '$.page_count');
SELECT json_extract(pdf_all(x''), '$.pdf_version');
SELECT json_extract(pdf_all(x''), '$.is_encrypted');

------------------------------------------------------------------
-- Acceptance 6: random bytes -> every fn NULL (no error)
------------------------------------------------------------------
SELECT pdf_title(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_author(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_subject(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_creator(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_producer(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_creation_date(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_mod_date(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_page_count(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_pdf_version(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_is_encrypted(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_keywords(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT pdf_all(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');

------------------------------------------------------------------
-- Acceptance 7: NULL input -> every fn NULL
------------------------------------------------------------------
SELECT pdf_title(NULL);
SELECT pdf_page_count(NULL);
SELECT pdf_all(NULL);

------------------------------------------------------------------
-- Acceptance 8: version is non-empty TEXT
------------------------------------------------------------------
SELECT length(pdf_meta_version()) > 0;
